Here's the full setup:

**XAML ‚Äî wrap CollectionView in RefreshView:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="48" HeightRequest="48" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}"
                               FontSize="12" TextColor="Gray" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center" VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel (using CommunityToolkit.Mvvm):**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}?id={SelectedItem.Id}");

        // Clear selection so user can re-select the same item
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Stops the refresh spinner
        }
    }
}
```

**Key bindings explained:**

| Property | Binds to | Purpose |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Controls the refresh spinner; set `false` when done |
| `Command` (RefreshView) | `RefreshCommand` | Generated by `[RelayCommand]` on `Refresh()` |
| `SelectedItem` | `Item? SelectedItem` | Two-way so the VM can clear it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap; triggers navigation |
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |

**Important details:**
- Use `ObservableCollection<T>`, not `List<T>`, so the UI updates automatically.
- Set `x:DataType` on `DataTemplate` for compiled bindings.
- Clear `SelectedItem` after navigating so the same item can be re-selected.
- Always set `IsRefreshing = false` in a `finally` block to guarantee the spinner stops.
- Update collections on the UI thread via `MainThread.BeginInvokeOnMainThread`.
